import pathlib
import urllib.parse
import time
import textwrap
import shutil
import yaml
import json

from python_on_whales import docker

from Deadline.open_studio_landscapes.constants import *
from Deadline.open_studio_landscapes.utils import *

from dagster import (
    asset,
    AssetIn,
    AssetExecutionContext,
    Output,
    AssetMaterialization,
    MetadataValue,
)


GROUP = "LikeC4"
KEY = "LikeC4"

asset_header = {
    "group_name": GROUP,
    "key_prefix": [KEY],
    "compute_kind": "python"
}


@asset(
    **asset_header,
    ins={
        "env_base": AssetIn(),
    },
)
def env(
        context: AssetExecutionContext,
        env_base: dict,
) -> dict:

    # @formatter:off
    _env = {
        "LIKEC4_DEV_PORT_HOST": "4567",
        "LIKEC4_DEV_PORT_CONTAINER": "4567",
        "LIKEC4_HOST": "0.0.0.0",
    }
    # @formatter:on

    env_base.update(_env)

    env_json = pathlib.Path(
        env_base["DOT_LANDSCAPES"],
        env_base.get("LANDSCAPE", "default"),
        "third_party",
        *context.asset_key.path,
        f"{context.asset_key.path[-1]}.json",
    )

    env_json.parent.mkdir(parents=True, exist_ok=True)

    with open(env_json, "w") as fw:
        json.dump(
            obj=_env.copy(),
            fp=fw,
            indent=2,
            ensure_ascii=True,
            sort_keys=True,
        )

    yield Output(env_base)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(env_base),
            "json": MetadataValue.path(env_json),
        },
    )


@asset(
    **asset_header,
    ins={
        "env": AssetIn(
            key_prefix=[KEY],
        ),
        "build_base_image": AssetIn(),
    },
)
def build(
        context: AssetExecutionContext,
        env: dict,
        build_base_image: str,
) -> str:
    """
    """

    docker_file = pathlib.Path(
        env["DOT_LANDSCAPES"],
        env.get("LANDSCAPE", "default"),
        "Dockerfiles",
        *context.asset_key.path,
        "Dockerfile",
    )

    tags = [
        f"{env.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:latest",
        # f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{str(time.time())}",
        f"{env.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{env.get('LANDSCAPE', str(time.time()))}",
    ]

    # @formatter:off
    docker_file_str = textwrap.dedent("""
        # {auto_generated}
        # {dagster_url}
        FROM {parent_image} AS {image_name}
        LABEL authors="{AUTHOR}"
        
        RUN apt-get update \
            && apt-get upgrade -y
        
        RUN apt-get install \
            -y \
            --no-install-recommends \
            unzip  \
            gpg  \
            gpg-agent
        
        WORKDIR /ENTRYPOINT
        
        COPY ./payload/setup.sh .
        COPY ./payload/run.sh .
        
        RUN chmod -R +x /ENTRYPOINT/*.sh
        
        RUN /usr/bin/env bash /ENTRYPOINT/setup.sh
        
        # https://stackoverflow.com/a/40454758/2207196
        ENTRYPOINT ["/usr/bin/env", "bash", "/ENTRYPOINT/run.sh", "yarn", "dev"]
        CMD []
    """).format(
        auto_generated=f"AUTO-GENERATED by Dagster Asset {context.asset_key.path[-1]}",
        dagster_url=urllib.parse.quote(f"http://localhost:3000/asset-groups/{context.asset_key.path[-1]}", safe=":/%"),
        image_name=context.asset_key.path[-1],
        parent_image=build_base_image,
        **env,
    )
    # @formatter:on

    shutil.rmtree(docker_file.parent, ignore_errors=True)

    docker_file.parent.mkdir(parents=True, exist_ok=True)

    with open(docker_file, "w") as fw:
        fw.write(docker_file_str)

    payload = docker_file.parent / "payload"
    payload.mkdir(parents=True, exist_ok=True)

    # setup.sh
    shutil.copy(
        src=pathlib.Path(
            env["CONFIGS_ROOT"],
            "likec4",
            "entrypoint",
            "setup.sh",
        ).expanduser(),
        dst=payload,
    )

    # run.sh
    shutil.copy(
        src=pathlib.Path(
            env["CONFIGS_ROOT"],
            "likec4",
            "entrypoint",
            "run.sh",
        ).expanduser(),
        dst=payload,
    )

    with open(docker_file, "r") as fr:
        docker_file_content = fr.read()

    stream = docker.build(
        context_path=docker_file.parent.as_posix(),
        cache=DOCKER_USE_CACHE,
        tags=tags,
        stream_logs=True,
    )

    log: str = ""

    for msg in stream:
        context.log.debug(msg)
        log += msg

    cmds_docker = compile_cmds(
        docker_file=docker_file,
        tag=tags[1],
    )

    yield Output(tags[1])

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.path(tags[1]),
            "docker_file": MetadataValue.md(f"```shell\n{docker_file_content}\n```"),
            **cmds_docker,
            "build_logs": MetadataValue.md(f"```shell\n{log}\n```"),
            "env": MetadataValue.json(env),
        },
    )


@asset(
    **asset_header,
    ins={
        "env": AssetIn(
            key_prefix=[KEY],
        ),
        "build": AssetIn(
            key_prefix=[KEY],
        ),
    },
)
def compose(
        context: AssetExecutionContext,
        env: dict,
        build: str,
) -> dict:
    """
    """

    docker_dict = {
        "services": {
            "likec4": {
                "container_name": "likec4",
                "hostname": "likec4",
                "domainname": env.get("ROOT_DOMAIN"),
                "restart": "always",
                "image": build,
                "networks": [
                    "repository",
                    "mongodb",
                ],
                "command": [
                    "--host",
                    env.get('LIKEC4_HOST'),
                    "--port",
                    env.get('LIKEC4_DEV_PORT_CONTAINER'),
                ],
                "volumes": [
                    f"{env.get('NFS_ENTRY_POINT')}:{env.get('NFS_ENTRY_POINT')}",
                    f"{env.get('NFS_ENTRY_POINT')}:{env.get('NFS_ENTRY_POINT_LNS')}",
                ],
                "healthcheck": {
                    "test": ["CMD", "curl", "-f", f"http://localhost:{env.get('LIKEC4_DEV_PORT_CONTAINER')}"],
                    "interval": "10s",
                    "timeout": "2s",
                    "retries": "3",
                },
                "ports": [
                    f"{env.get('LIKEC4_DEV_PORT_HOST')}:{env.get('LIKEC4_DEV_PORT_CONTAINER')}",
                ],
            },
        },
    }

    docker_yaml = yaml.dump(docker_dict)

    yield Output(docker_dict)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.json(docker_dict),
            "docker_dict": MetadataValue.md(f"```json\n{json.dumps(docker_dict, indent=2)}\n```"),
            "docker_yaml": MetadataValue.md(f"```yaml\n{docker_yaml}\n```"),
            "env": MetadataValue.json(env),
        },
    )
